const body = $json.body || $json;
const messages = body.messages || [];
const lastUserMsg = [...messages].reverse().find(m => m.role === 'user');
let userText = '';
let fileContent = '';
if (typeof lastUserMsg?.content === 'string') {
  userText = lastUserMsg.content;
} else if (Array.isArray(lastUserMsg?.content)) {
  for (const part of lastUserMsg.content) {
    if (part.type === 'text') userText += part.text || '';
    else if (part.type === 'file' || part.type === 'document') fileContent += part.file_data?.content || part.content || part.text || '';
  }
}
const userTextLower = userText.toLowerCase().trim();
const fullText = (userTextLower + ' ' + fileContent).toLowerCase();

// SCHWAB
const schwabKeywords = ['schwab','all clients','all client','all reports','all icp','generate all','bulk','multiple clients','from the file','from sharepoint','downloads folder','the file','export file','data file','uploaded file'];
const isSchwab = schwabKeywords.some(kw => fullText.includes(kw));

// ICP
const icpKeywords = ['generate icp','create icp','icp report','icp review','quarterly review','quarterly report','client review','generate report','create report','build report'];
const isICP = !isSchwab && icpKeywords.some(kw => fullText.includes(kw));
const hasClientData = fileContent && (fileContent.includes('CLIENT_NAME') || fileContent.includes('ACCOUNT_NUMBER') || fileContent.includes('PORTFOLIO_VALUE') || fileContent.includes('YTD_RETURN'));

// MARKET DATA - ticker/price questions
const marketKeywords = ['trading at','stock price','share price','what is aapl','what is msft','what is nvda','what is tsla','what is amzn','what is googl','what is meta','what is spy','what is qqq','what is dia','what is iwm','stock quote','market price','price of','price for','how is the market','market today','market doing','s&p today','nasdaq today','dow today','index today','etf price','bond yield','10 year yield','2 year yield','vix today','vix at','gold price','oil price','bitcoin price'];
const hasExplicitTicker = /\b[A-Z]{2,5}\b/.test(userText) && (fullText.includes('price') || fullText.includes('trading') || fullText.includes('quote') || fullText.includes('stock') || fullText.includes('ticker') || fullText.includes('at today') || fullText.includes('right now'));
const isMarket = !isSchwab && !isICP && (marketKeywords.some(kw => fullText.includes(kw)) || hasExplicitTicker);

let route = 'GENERAL';
if (isSchwab) route = 'SCHWAB';
else if (isICP || hasClientData) route = 'ICP';
else if (isMarket) route = 'MARKET';

console.log('Route:', route, '| text:', userTextLower.substring(0,80));
return [{ json: { route, userMessage: lastUserMsg?.content || '', userText: userTextLower || fileContent.substring(0, 500), fileContent, hasFile: fileContent.length > 0, originalBody: body, messages } }];

